// src/nodes/deleteNode.js
import React from "react";
import "./node.css";

export const DeleteNode = ({ data }) => {
  const handleDelete = () => {
    if (data.onDelete && data.targetId) {
      data.onDelete(data.targetId); // deletes the chosen target node
    }
  };

  return (
    <div className="vs-node delete-node">
      <div className="vs-node-header">Delete Node</div>
      <p>Target: {data.targetId || "None"}</p>
      <button onClick={handleDelete}>Delete Target</button>
    </div>
  );
};
